import React, { useState, useEffect } from 'react';
import { getTrucks, getSources, getCustomers, createTrip } from '../api';
import { bsToADString, formatBS } from '../nepaliDate';
import NepaliDatePicker from './NepaliDatePicker';
import toast from 'react-hot-toast';

const FOODING_RATE = 1000;
const BHATTA_RATE  = 1500;
const DIESEL_PRICE = 222.5;

const initialForm = {
  truck_id:         '',
  source_id:        '',
  customer_id:      '',
  mpp_bill_no:      '',
  diesel_used:      '',
  loading_amount:   '',
  unloading_amount: '',
  freight_amount:   '',
  remarks:          '',
};

const emptyBS = { year: '', month: '', day: '' };

export default function TripForm({ onSuccess }) {
  const [form, setForm]           = useState(initialForm);
  const [startBS, setStartBS]     = useState(emptyBS);
  const [endBS, setEndBS]         = useState(emptyBS);
  const [trucks, setTrucks]       = useState([]);
  const [sources, setSources]     = useState([]);
  const [customers, setCustomers] = useState([]);
  const [selectedTruck, setSelectedTruck]       = useState(null);
  const [selectedCustomer, setSelectedCustomer] = useState(null);
  const [distanceKm, setDistanceKm]             = useState(null);
  const [submitting, setSubmitting]             = useState(false);

  // Convert BS dates to AD strings for calculations
  const startAD = bsToADString(startBS.year, startBS.month, startBS.day);
  const endAD   = bsToADString(endBS.year,   endBS.month,   endBS.day);

  // Number of days
  const numDays = (() => {
    if (!startAD || !endAD) return null;
    const ms = new Date(endAD) - new Date(startAD);
    const d = Math.ceil(ms / (1000 * 60 * 60 * 24));
    return d > 0 ? d : null;
  })();

  const fooding    = numDays ? numDays * FOODING_RATE : 0;
  const tripBhatta = numDays ? numDays * BHATTA_RATE  : 0;

  const truckAvg     = selectedTruck?.avg_kmpl ? parseFloat(selectedTruck.avg_kmpl) : null;
  const dieselNeeded = distanceKm && truckAvg ? (distanceKm / truckAvg).toFixed(2) : null;
  const dieselCost   = form.diesel_used ? (parseFloat(form.diesel_used) * DIESEL_PRICE).toFixed(2) : null;
  const dieselDev    = dieselNeeded && form.diesel_used
    ? (parseFloat(dieselNeeded) - parseFloat(form.diesel_used)).toFixed(2)
    : null;

  const totalExpenses =
    (parseFloat(dieselCost)             || 0) +
    fooding + tripBhatta +
    (parseFloat(form.loading_amount)    || 0) +
    (parseFloat(form.unloading_amount)  || 0);

  const surplus = form.freight_amount
    ? (parseFloat(form.freight_amount) - totalExpenses).toFixed(2)
    : null;

  useEffect(() => {
    getTrucks().then(setTrucks);
    getSources().then(setSources);
    getCustomers().then(setCustomers);
  }, []);

  useEffect(() => {
    const t = trucks.find(t => t.id === parseInt(form.truck_id));
    setSelectedTruck(t || null);
  }, [form.truck_id, trucks]);

  useEffect(() => {
    const c = customers.find(c => c.id === parseInt(form.customer_id));
    setSelectedCustomer(c || null);
    setDistanceKm(c?.distance_km ?? null);
  }, [form.customer_id, customers]);

  const handleChange = e => {
    const { name, value } = e.target;
    setForm(prev => ({ ...prev, [name]: value }));
  };

  const handleSubmit = async e => {
    e.preventDefault();
    if (!form.truck_id || !form.source_id || !form.customer_id) {
      toast.error('Please fill all required fields.');
      return;
    }
    if (!startAD) {
      toast.error('Please select a start date.');
      return;
    }
    setSubmitting(true);
    try {
      await createTrip({
        ...form,
        start_date:       startAD,
        end_date:         endAD || null,
        distance_km:      distanceKm,
        diesel_needed:    dieselNeeded,
        diesel_cost:      dieselCost,
        loading_unloading: (parseFloat(form.loading_amount) || 0) + (parseFloat(form.unloading_amount) || 0),
      });
      toast.success('Trip entry saved!');
      setForm(initialForm);
      setStartBS(emptyBS);
      setEndBS(emptyBS);
      setDistanceKm(null);
      onSuccess?.();
    } catch (err) {
      toast.error(err.response?.data?.error || 'Failed to save trip.');
    } finally {
      setSubmitting(false);
    }
  };

  const fmt = n => n != null ? `NPR ${Number(n).toLocaleString()}` : '—';

  return (
    <form onSubmit={handleSubmit} style={styles.form}>
      <h2 style={styles.heading}>New Trip Entry</h2>

      {/* ── 1. Truck ── */}
      <Section title="1. Truck & Driver">
        <Row>
          <Field label="Truck Number *">
            <select name="truck_id" value={form.truck_id} onChange={handleChange} style={styles.input} required>
              <option value="">Select truck</option>
              {trucks.map(t => <option key={t.id} value={t.id}>{t.truck_number}</option>)}
            </select>
          </Field>
          <Field label="Driver Name">
            <input value={selectedTruck?.driver_name || '—'} readOnly style={styles.readOnly} />
          </Field>
        </Row>
      </Section>

      {/* ── 2. Source ── */}
      <Section title="2. Source">
        <Field label="From (Source) *">
          <select name="source_id" value={form.source_id} onChange={handleChange} style={styles.input} required>
            <option value="">Select source</option>
            {sources.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
          </select>
        </Field>
      </Section>

      {/* ── 3. Trip Details ── */}
      <Section title="3. Trip Details">
        <Row>
          <NepaliDatePicker
            label="Start Date"
            value={startBS}
            onChange={setStartBS}
            required
          />
          <NepaliDatePicker
            label="End Date"
            value={endBS}
            onChange={setEndBS}
          />
        </Row>

        {numDays && (
          <InfoBox style={{ background: '#e8f0fe', borderColor: '#a8c0e8' }}>
            🗓 Trip duration: <b>{numDays} day{numDays > 1 ? 's' : ''}</b>
            &nbsp;({formatBS(startBS)} → {formatBS(endBS)})
          </InfoBox>
        )}

        <Field label="Customer (Destination) *">
          <select name="customer_id" value={form.customer_id} onChange={handleChange} style={styles.input} required>
            <option value="">Select customer</option>
            {customers.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
          </select>
        </Field>

        {selectedCustomer && (
          <InfoBox>
            <b>Destination:</b> {selectedCustomer.destination_address || '⚠ Address not set'}&nbsp;&nbsp;
            <b>Distance:</b> {distanceKm ? `${distanceKm} km` : '—'}&nbsp;&nbsp;
            <b>Freight:</b> {fmt(selectedCustomer.freight_actual)}
          </InfoBox>
        )}
      </Section>

      {/* ── 4. MPP Bill ── */}
      <Section title="4. MPP Bill Number">
        <Field label="MPP Bill No.">
          <input type="text" name="mpp_bill_no" value={form.mpp_bill_no} onChange={handleChange} style={styles.input} placeholder="e.g. 5531" />
        </Field>
      </Section>

      {/* ── 5. Diesel ── */}
      <Section title="5. Diesel">
        <Row>
          <Field label="Diesel Needed (L) — Auto">
            <input
              value={dieselNeeded != null ? `${dieselNeeded} L` : '—'}
              readOnly
              style={{ ...styles.readOnly, background: dieselNeeded ? '#e8f5e9' : '#f0f4f8', color: dieselNeeded ? '#1b5e20' : '#999', fontWeight: 600 }}
            />
          </Field>
          <Field label="Diesel Used (L)">
            <input type="number" name="diesel_used" value={form.diesel_used} onChange={handleChange} style={styles.input} step="0.01" placeholder="e.g. 148" />
          </Field>
        </Row>
        <Row>
          <Field label={`Diesel Cost (NPR) — Auto (${DIESEL_PRICE}/L)`}>
            <input value={dieselCost != null ? fmt(dieselCost) : '—'} readOnly style={{ ...styles.readOnly, fontWeight: 600 }} />
          </Field>
          <Field label="Deviation (L) — needed − used">
            <input
              value={dieselDev != null ? `${dieselDev} L` : '—'}
              readOnly
              style={{ ...styles.readOnly, color: dieselDev < 0 ? '#cc0000' : dieselDev > 0 ? '#007700' : '#555' }}
            />
          </Field>
        </Row>
      </Section>

      {/* ── 6. Allowances ── */}
      <Section title="6. Allowances — Auto">
        <Row>
          <Field label="Days">
            <input value={numDays ?? '—'} readOnly style={styles.readOnly} />
          </Field>
          <Field label={`Fooding (NPR ${FOODING_RATE}/day)`}>
            <input value={fooding ? fmt(fooding) : '—'} readOnly style={styles.readOnly} />
          </Field>
          <Field label={`Trip Bhatta (NPR ${BHATTA_RATE}/day)`}>
            <input value={tripBhatta ? fmt(tripBhatta) : '—'} readOnly style={styles.readOnly} />
          </Field>
        </Row>
      </Section>

      {/* ── 7. Loading & Unloading ── */}
      <Section title="7. Loading & Unloading">
        <Row>
          <Field label="Loading Amount (NPR)">
            <input type="number" name="loading_amount" value={form.loading_amount} onChange={handleChange} style={styles.input} placeholder="e.g. 300" />
          </Field>
          <Field label="Unloading Amount (NPR)">
            <input type="number" name="unloading_amount" value={form.unloading_amount} onChange={handleChange} style={styles.input} placeholder="e.g. 500" />
          </Field>
        </Row>
      </Section>

      {/* ── 8. Summary ── */}
      <Section title="8. Summary">
        <Field label="Freight Amount (NPR)">
          <input type="number" name="freight_amount" value={form.freight_amount} onChange={handleChange} style={styles.input} placeholder="e.g. 30000" />
        </Field>
        <Row>
          <Field label="Total Expenses — Auto">
            <input value={fmt(totalExpenses)} readOnly style={{ ...styles.readOnly, fontWeight: 'bold', fontSize: 15 }} />
          </Field>
          <Field label="Surplus — Auto">
            <input
              value={surplus != null ? fmt(surplus) : '—'}
              readOnly
              style={{ ...styles.readOnly, fontWeight: 'bold', fontSize: 15, color: surplus < 0 ? '#cc0000' : '#007700' }}
            />
          </Field>
        </Row>
      </Section>

      <Section title="Remarks (Optional)">
        <textarea name="remarks" value={form.remarks} onChange={handleChange}
          style={{ ...styles.input, height: 70, resize: 'vertical' }} placeholder="Any notes..." />
      </Section>

      <button type="submit" disabled={submitting} style={styles.submitBtn}>
        {submitting ? 'Saving...' : 'Save Trip Entry'}
      </button>
    </form>
  );
}

function Section({ title, children }) {
  return <div style={styles.section}><div style={styles.sectionTitle}>{title}</div>{children}</div>;
}
function Row({ children }) { return <div style={styles.row}>{children}</div>; }
function Field({ label, children }) {
  return <div style={styles.field}><label style={styles.label}>{label}</label>{children}</div>;
}
function InfoBox({ children, style }) {
  return <div style={{ ...styles.infoBox, ...style }}>{children}</div>;
}

